#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-.5) * uAspect.xy;


vec2 uv6 = uv1;
float z = .2*q28*length(uv1)+rand_frame * 64;
vec2 d = normalize(uv1);
float clp = .5+rand_preset*10;
vec2 rs = clamp(tan(z)*d,-clp,clp);
vUv += rs/20;


uv6 = .4*sin(uv1*2*(4+q28));
mus = .06/(length(uv6));
mus *= roam_cos;

vec3 blur = GetBlur1(fract(vUv));

vec3 crisp= texture(sampler_main,vUv);

vec3 ret1 = crisp - blur*.04 + .15*mus;

//ret1 = mix(ret1,ret1.gbr,lum(ret1));
q25 = q24+.01;
ret = q25*(ret1-.02)*.98 + (1-q25)* (GetPixel(vUvOriginal)-.0015);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

vUv = multiply(vUv, mat2(_qb));

float dist = 1;
float inten = 1;
ret1 = 0;
int anz = 4;
float n = anz;
while (n >= 0) {
    ang2 = 0*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
//uv2 = vUv;
    dist = 1-fract(1.0/anz*n+q30); //evtl sqrt !
    inten =  sqrt(dist)*(1-dist)*2;
vec2 uv3 = 3*uv2*dist*(1+q5*vUv.x) + 0.5 +vec2(q18*n,q19) ;

vec3 cmul = vec3(dist,1-dist,1-(dist-.5)*(dist-.5)*4);
    neu = texture(sampler_main,uv3) +q6*GetBlur1(fract(uv3*1.04)).bgr*1;

//    neu = neu*cmul;
     ret1 = max(ret1,neu*inten);
n--;
}

ret1 = mix(ret1,ret1.gbr,q26/6);
ret = ret1*2 + (1-vRadius)*q26/3*GetPixel(q5/2+vUv*(2-vRadius));


  fragColor = ret;
}
